import React, { useState, useEffect } from 'react';
import PropertyCard from '../components/PropertyCard';
import SearchBar from '../components/SearchBar';

const Home = () => {
  const [properties, setProperties] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Fetch properties from API
    const fetchProperties = async () => {
      try {
        const response = await fetch('http://localhost:3001/api/properties');
        if (response.ok) {
          const data = await response.json();
          setProperties(data);
        } else {
          // Fallback to mock data if API fails or is empty
          setProperties([
            {
              id: 1,
              title: 'Luxury Villa with Ocean View',
              location: 'Goa, India',
              pricePerNight: 15000,
              rating: 4.8,
              images: ['https://images.unsplash.com/photo-1613490493576-7fde63acd811?ixlib=rb-4.0.3&auto=format&fit=crop&w=1171&q=80']
            },
            {
              id: 2,
              title: 'Mountain Retreat Resort',
              location: 'Manali, India',
              pricePerNight: 8000,
              rating: 4.5,
              images: ['https://images.unsplash.com/photo-1566073771259-6a8506099945?ixlib=rb-4.0.3&auto=format&fit=crop&w=1170&q=80']
            },
            {
              id: 3,
              title: 'Cozy Cottage in the Woods',
              location: 'Ooty, India',
              pricePerNight: 5000,
              rating: 4.9,
              images: ['https://images.unsplash.com/photo-1587061949409-02df41d5e562?ixlib=rb-4.0.3&auto=format&fit=crop&w=1170&q=80']
            }
          ]);
        }
      } catch (error) {
        console.error('Error fetching properties:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchProperties();
  }, []);

  const handleSearch = (searchParams) => {
    console.log('Searching with:', searchParams);
    // Implement search logic here
  };

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Hero Section */}
      <div className="bg-white border-b border-gray-200 sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <SearchBar onSearch={handleSearch} />
        </div>
      </div>

      {/* Property Grid */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {loading ? (
          <div className="text-center py-10">Loading properties...</div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
            {properties.map((property) => (
              <PropertyCard key={property.id} property={property} />
            ))}
          </div>
        )}
      </main>
    </div>
  );
};

export default Home;
